    event_month: "May",
    event_name: "Salon AI Dinner — Munich",
    event_sub: "Luitpoldblock · 18:00 doors · 18:15 start · Modern Middle Eastern Cuisine · Drinks included · €78",
    event_laptop: "A laptop is enough — preparation details come with the reservation.",
