    host_own_geo: "Currently only in Munich and Berlin. Interested in Stockholm, Milan, Hamburg, London or Madrid? <a href=\"mailto:franziska.wittleder@gmail.com\" style=\"color:rgba(255,255,255,0.55);text-decoration:underline;\">Write to us.</a>",
    host_own_btn: "Host your own evening →",
    host_own_fine: "You pick the date · enter your name · receive a ready-to-share link · from min. 12 people · €78 incl. catering",
    faq_label: "FAQ",
    faq_h2: "Frequently asked questions",
    faq_q1: "Who hosts the Salon?",
